={
  "query": "query Transcripts($limit: Int) { transcripts(limit: $limit) { id title date duration transcript_url meeting_attendees { displayName email } sentences { text speaker_name } } }",
  "variables": { "limit": 5 }
}

parameters.jsCode:
// Transkript-Text zusammenbauen + PII-Längenbegrenzung gegen Prompt-Injection & Token-Explosion
const items = [];
for (const item of $input.all()) {
  const t = item.json;
  const sentences = Array.isArray(t.sentences) ? t.sentences : [];
  // Sprecher + Text, Steuerzeichen entschärfen, hart kürzen (~24k Zeichen ~ 6k Tokens)
  let transcriptText = sentences
    .map(s => `${(s.speaker_name || 'Sprecher').toString().slice(0, 60)}: ${(s.text || '').toString().replace(/[`\u0000-\u001F]/g, ' ')}`)
    .join('\n');
  const MAX = 24000;
  let truncated = false;
  if (transcriptText.length > MAX) {
    transcriptText = transcriptText.slice(0, MAX);
    truncated = true;
  }
  const attendees = Array.isArray(t.meeting_attendees) ? t.meeting_attendees : [];
  items.push({
    json: {
      meetingId: t.id || null,
      title: (t.title || 'Unbenanntes Meeting').toString().slice(0, 200),
      date: t.date || null,
      durationMin: t.duration ? Math.round(Number(t.duration) / 60) : null,
      attendees: attendees.map(a => ({ name: a.displayName || null, email: a.email || null })),
      transcriptUrl: t.transcript_url || null,
      transcriptText,
      truncated,
    }
  });
}
return items;

