parameters.jsCode:
// Claude-Antwort robust parsen + Pass-Through der Meeting-Metadaten
const out = [];
for (const item of $input.all()) {
  const resp = item.json;
  // Anthropic messages-API: content[0].text
  let raw = '';
  try { raw = resp.content && resp.content[0] && resp.content[0].text ? resp.content[0].text : ''; } catch (e) { raw = ''; }
  let parsed = null;
  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    // Fallback: erstes JSON-Objekt aus Text extrahieren
    const m = raw.match(/\{[\s\S]*\}/);
    if (m) { try { parsed = JSON.parse(m[0]); } catch (e2) { parsed = null; } }
  }
  // Meeting-Metadaten aus dem Prepare-Node (gleicher Item-Index)
  let meta = {};
  try { meta = $('Code: Transkript aufbereiten').item.json; } catch (e) { meta = {}; }
  if (!parsed) {
    throw new Error('LLM-Antwort nicht als JSON parsebar für Meeting: ' + (meta.title || 'unbekannt'));
  }
  out.push({
    json: {
      meetingId: meta.meetingId || null,
      title: meta.title || 'Meeting',
      date: meta.date || null,
      durationMin: meta.durationMin || null,
      attendees: meta.attendees || [],
      transcriptUrl: meta.transcriptUrl || null,
      truncated: meta.truncated || false,
      summary: parsed.summary || '',
      decisions: Array.isArray(parsed.decisions) ? parsed.decisions : [],
      actionItems: Array.isArray(parsed.action_items) ? parsed.action_items : [],
      nextMeeting: parsed.next_meeting || null,
      sentiment: parsed.sentiment || 'neutral',
    }
  });
}
return out;

