// Sammelt alle Fehler-Pfade (Fireflies-Fetch, LLM, CRM) in eine Alert-Nachricht
const errors = [];
for (const item of $input.all()) {
  const j = item.json || {};
  const errMsg = (j.error && (j.error.message || j.error)) || j.message || JSON.stringify(j).slice(0, 300);
  errors.push({
    json: {
      alert: '🚨 Meeting-Summarizer Fehler',
      stage: j.title ? ('Meeting: ' + j.title) : 'Pipeline',
      detail: String(errMsg).slice(0, 500),
      ts: new Date().toISOString(),
    }
  });
}
return errors.length ? errors : [{ json: { alert: '🚨 Meeting-Summarizer Fehler', stage: 'Pipeline', detail: 'Unbekannter Fehler im Workflow', ts: new Date().toISOString() } }];
